windowclass.script:
			function update()
				super.update();

				bReadOnly = WindowManager.getReadOnlyState(getDatabaseNode());
				button_collapse_all.setVisible(not bReadOnly);
				button_expand_all.setVisible(not bReadOnly);
				if bReadOnly then
					if parentcontrol.window.main and parentcontrol.window.main.subwindow then
						parentcontrol.window.main.subwindow.expandSubwindows();
					end
				end
			end

