windowclass.script:
			function onInit()
				self.update();
			end
			function update()
				local nodeRecord = getDatabaseNode();
				local bReadOnly = WindowManager.getReadOnlyState(nodeRecord);
				local bID = ItemManager.getIDState(nodeRecord);

				local tFields = {
					"armortype", "defensebonus", "armor_mm_skill",
					"protection_head", "protection_face", "protection_neck",
					"protection_torso", "protection_arms", "protection_legs",
					};
				WindowManager.callSafeControlsUpdate(self, tFields, bReadOnly, not bID);

				local tPenaltyFields = { "minimum_mm_penalty", "maximum_mm_penalty", "missile_penalty", "quickness_penalty", };
				WindowManager.callSafeControlsSetLockMode(self, tPenaltyFields, bReadOnly);
				if (bID or Session.IsHost) and (not minimum_mm_penalty.isEmpty() or not maximum_mm_penalty.isEmpty() or
									not missile_penalty.isEmpty() or not quickness_penalty.isEmpty()) then 
					bArmorPenalties = true;
				else
					bArmorPenalties = false;
				end
				local bShowPenalties = bID and (not bReadOnly or bArmorPenalties);
				WindowManager.setControlVisibleWithLabel(self, "minimum_mm_penalty", bShowPenalties);
				WindowManager.setControlVisibleWithLabel(self, "maximum_mm_penalty", bShowPenalties);
				WindowManager.setControlVisibleWithLabel(self, "missile_penalty", bShowPenalties);
				WindowManager.setControlVisibleWithLabel(self, "quickness_penalty", bShowPenalties);

				local bShow = WindowManager.getAnyControlVisible(self, tFields);
				armor_penalties_label.setVisible(bShowPenalties);
				armor_penalties_spacer.setVisible(bShowPenalties);
				divider.setVisible(bShow or bShowPenalties);
			end

combobox_columnh_item.script:
function onInit()
	super.onInit();
	if Rules_Skills.ManeuveringInArmorSkillList then
		local skillList = Rules_Skills.ManeuveringInArmorSkillList();
		if skillList and #skillList > 0 then
			addItems(skillList);
		else
			window.armor_mm_skill_label.setVisible(false);
			window.armor_mm_skill.setVisible(false);
			setVisible(false);
		end
	end
end

windowclass.script:
			function onInit()
				self.update();
			end
			function update()
				local nodeRecord = getDatabaseNode();
				local bReadOnly = WindowManager.getReadOnlyState(nodeRecord);
				local bID = ItemManager.getIDState(nodeRecord);

				local tFields = { "meleebonus", "missilebonus", };
				WindowManager.callSafeControlsUpdate(self, tFields, bReadOnly, not bID);
				divider.setVisible(WindowManager.getAnyControlVisible(self, tFields));
			end

			function onInit()
				self.update();

				Module.onModuleLoad = ModuleLoadUnload;
				Module.onModuleUnload = ModuleLoadUnload;
				ModuleLoadUnload();
			end
			function ModuleLoadUnload()
				Rules_Tables.LoadLists();
				
				fumbletable.setItems(Rules_Tables.FumbleTableList());
				self.onFumbleTableChanged();

				attacktablename.setItems(Rules_Tables.TableList());
				altcrit1name.setItems(Rules_Tables.TableList(Rules_Tables.TypeResult, Rules_Tables.ClassCritical));
				altcrit2name.setItems(Rules_Tables.TableList(Rules_Tables.TypeResult, Rules_Tables.ClassCritical));
				altcrit3name.setItems(Rules_Tables.TableList(Rules_Tables.TypeResult, Rules_Tables.ClassCritical));
				addcrit1name.setItems(Rules_Tables.TableList(Rules_Tables.TypeResult, Rules_Tables.ClassCritical));
				addcrit2name.setItems(Rules_Tables.TableList(Rules_Tables.TypeResult, Rules_Tables.ClassCritical));
			end
			function onFumbleTableChanged()
				fumblecolumn.setItems(Rules_Tables.FumbleTableColumnList(fumbletable.getValue()));
			end
			function update()
				local nodeRecord = getDatabaseNode();
				local bReadOnly = WindowManager.getReadOnlyState(nodeRecord);
				local bID = ItemManager.getIDState(nodeRecord);

				local tWeaponFields = { "fumbletable", "fumblecolumn", "fumble", "weaponbonus", "ob", "hitsmultiplier", "associatedskill", "skillbonus", };
				WindowManager.callSafeControlSetLockMode(self, "fumbletable", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "fumbletable", bID and (not bReadOnly or not fumbletable.isEmpty()));
				WindowManager.callSafeControlsUpdate(self, { "fumblecolumn", "fumble", "weaponbonus", "ob", "hitsmultiplier", }, bReadOnly, not bID);
				self.updateSkill(bReadOnly, bID);
				local bShow = WindowManager.getAnyControlVisible(self, tWeaponFields);
				divider.setVisible(bShow);
				ob.refresh();

				local tAttackFields = { "attacktablename", "criticaltable", "largecolumnname", "max_rank_size", };
				WindowManager.callSafeControlSetLockMode(self, "attacktablename", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "attacktablename", bID and (not bReadOnly or not attacktablename.isEmpty()));
				WindowManager.callSafeControlsUpdate(self, { "criticaltable", "largecolumnname", "max_rank_size", }, bReadOnly, not bID);
				local bShowAttack = WindowManager.getAnyControlVisible(self, tAttackFields);
				attacktable_label.setVisible(bShowAttack);
				attacktable_spacer.setVisible(bShowAttack);
				dividerAttack.setVisible(bShowAttack);

				local tAltCritFields = { "altcrit1name", "altcrit2name", "altcrit3name", "altcrit1mod", "altcrit2mod", "altcrit3mod", };
				WindowManager.callSafeControlSetLockMode(self, "altcrit1name", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "altcrit1name", bID and (not bReadOnly or not altcrit1name.isEmpty()));
				WindowManager.callSafeControlSetLockMode(self, "altcrit2name", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "altcrit2name", bID and (not bReadOnly or not altcrit2name.isEmpty()));
				WindowManager.callSafeControlSetLockMode(self, "altcrit3name", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "altcrit3name", bID and (not bReadOnly or not altcrit3name.isEmpty()));
				WindowManager.callSafeControlsUpdate(self, { "altcrit1mod", "altcrit2mod", "altcrit3mod", }, bReadOnly, not bID);
				local bShowAltCrit = WindowManager.getAnyControlVisible(self, tAltCritFields);
				altcritable_label.setVisible(bShowAltCrit);
				altcritable_spacer.setVisible(bShowAltCrit);
				dividerAltCrits.setVisible(bShowAltCrit);

				local tAddCritFields = { "addcrit1name", "addcrit2name", "addcrit1leveldiff", "addcrit2leveldiff", };
				WindowManager.callSafeControlSetLockMode(self, "addcrit1name", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "addcrit1name", bID and (not bReadOnly or not addcrit1name.isEmpty()));
				WindowManager.callSafeControlSetLockMode(self, "addcrit2name", bReadOnly);
				WindowManager.setControlVisibleWithLabel(self, "addcrit2name", bID and (not bReadOnly or not addcrit2name.isEmpty()));
				WindowManager.callSafeControlsUpdate(self, { "addcrit1leveldiff", "addcrit2leveldiff", }, bReadOnly, not bID);
				local bShowAddCrit = WindowManager.getAnyControlVisible(self, tAddCritFields);
				addcritable_label.setVisible(bShowAddCrit);
				addcritable_spacer.setVisible(bShowAddCrit);
				dividerAddCrits.setVisible(bShowAddCrit);

				local tRangeFields = { "rng1", "rngmod1", "rng2", "rngmod2", "rng3", "rngmod3", "rng4", "rngmod4", "rng5", "rngmod5", "rng6", "rngmod6", };
				WindowManager.callSafeControlsUpdate(self, tRangeFields, bReadOnly, not bID);
				local bShowRange = WindowManager.getAnyControlVisible(self, tRangeFields);
				range_mods_label.setVisible(bShowRange);
				range_mods_spacer.setVisible(bShowRange);
				dividerRange.setVisible(bShowRange);

				local tVsATFields = { "at1_4", "at5_8", "at9_12", "at13_16", "at17_20", };
				WindowManager.callSafeControlsUpdate(self, tVsATFields, bReadOnly, not bID);
				local bShowVsAT = WindowManager.getAnyControlVisible(self, tVsATFields);
				self.showAdjVsAT(bShowVsAT);
				dividerVsAT.setVisible(bShowVsAT);
			end
			function updateSkill(bReadOnly, bID)
				local nodeChar = DB.getChild(getDatabaseNode(), "...");
				if ActorManager.getRecordType(nodeChar) == "charsheet" then
					WindowManager.callSafeControlsUpdate(self, { "associatedskill", "skillbonus", }, bReadOnly, not bID);
				else
					WindowManager.setControlVisibleWithLabel(self, "associatedskill", false);
					WindowManager.setControlVisibleWithLabel(self, "skillbonus", false);
				end
			end
			function showAdjVsAT(bShow)
				WindowManager.setControlVisibleWithLabel(self, "at1_4", bShow);
				WindowManager.setControlVisibleWithLabel(self, "at5_8", bShow);
				WindowManager.setControlVisibleWithLabel(self, "at9_12", bShow);
				WindowManager.setControlVisibleWithLabel(self, "at13_16", bShow);
				WindowManager.setControlVisibleWithLabel(self, "at17_20", bShow);
				adj_vs_at_label.setVisible(bShow);
				adj_vs_at_spacer.setVisible(bShow);
			end

combobox_columnh_item.script:
function onInit()
	super.onInit();
	refresh();
end
function refresh()
	local nodeChar = DB.getChild(window.getDatabaseNode(), "...");
	local sType = ActorManager.getRecordType(nodeChar);
	if sType == "charsheet" then
		local skillList = Rules_PC.SkillList(nodeChar);
		if #skillList > 0 then
			addItems(skillList);
		end
	else
		window.associatedskill_label.setVisible(false);
		window.associatedskill.setVisible(false);
		setVisible(false);
	end
end

number_columnh_item.script:
function onInit()
	super.onInit();
	local node = window.getDatabaseNode();
	DB.addHandler(DB.getPath(node, "associatedskill"), "onUpdate", self.refresh);
	self.refresh();
end
function refresh()
	local nodeChar = DB.getChild(window.getDatabaseNode(), "...");
	local sType = ActorManager.getRecordType(nodeChar);
	if sType == "charsheet" then
		local nodeSkillBonus = getDatabaseNode();
		if nodeSkillBonus then
			local sAssociatedSkill = window.associatedskill.getValue();
			if sAssociatedSkill then
				local nNewOB = Rules_PC.SkillTotal(nodeChar, sAssociatedSkill);
				if nNewOB and nNewOB ~= -25 then
					nodeSkillBonus.setValue(nNewOB);
				end
			end
		end
	else
		window.skillbonus_label.setVisible(false);
		setVisible(false);
	end
end

					function onInit()
						super.onInit();

						local node = window.getDatabaseNode();
						DB.addHandler(DB.getPath(node, "weaponbonus"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "skillbonus"), "onUpdate", self.refresh);
						self.refresh();
					end
					function refresh()
						local nodeChar = DB.getChild(window.getDatabaseNode(), "...");
						local sType = ActorManager.getRecordType(nodeChar);
						if sType == "charsheet" then
							local nodeItem = window.getDatabaseNode();
							local bID = (DB.getValue(nodeItem, "isidentified", 1) == 1);
							if bID then
								setValue(window.skillbonus.getValue() + window.weaponbonus.getValue());	
								window.ob_nonid.setValue(0);
							else
								setValue(window.skillbonus.getValue());	
								window.ob_nonid.setValue(window.weaponbonus.getValue());
							end
						end
					end

combobox_columnh_item.script:
function onInit()
	super.onInit();
	setValue(Rules_Combat.GetMaxRankSize(window.max_level.getValue()));
	updateList();
end
function onValueChanged()
	if super and super.onValueChanged then
		super.onValueChanged();
	end
	window.max_level.setValue(Rules_Combat.GetMaxLevel(getValue()));					
end
function updateList()
	local maxRankSizeList = Rules_Combat.MaxRankSizeList();
	if #maxRankSizeList > 0 then
		clear();
		addItems(maxRankSizeList);
	end
end

function onInit()
	super.onInit();
	DB.addHandler(DB.getPath(window.attacktablename.getDatabaseNode()), "onUpdate", onUpdate);
	onUpdate();
	updateList();
end
function onClose()
	DB.removeHandler(DB.getPath(window.attacktablename.getDatabaseNode()), "onUpdate", onUpdate);
	super.onClose();
end
function onUpdate()
	local sAttackTableName = window.attacktablename.getValue();
	if string.len(getValue()) < 1 and string.len(sAttackTableName) > 0 then
		setValue("Attack Default");
		window.largecolumnname.setValue("Normal");
		if window.hitsmultiplier.getValue() == 0 then
			window.hitsmultiplier.setValue(1);
		end
	elseif string.len(getValue()) > 0 and string.len(sAttackTableName) < 1 then
		setValue("");
		window.largecolumnname.setValue("");
		if window.hitsmultiplier.getValue() == 1 then
			window.hitsmultiplier.setValue(0);
		end
	end
end
function updateList()
	local critList = {"", "Attack Default", "Alternate Crit #1", "Alternate Crit #2", "Alternate Crit #3" };
	if #critList > 0 then
		clear();
		addItems(critList);
	end
end

					function onInit()
						super.onInit();

						local sAttackTableName = window.attacktablename.getValue();
						if string.len(getValue()) < 1 and string.len(sAttackTableName) > 0 then
							setValue("Normal");
						elseif string.len(getValue()) > 0 and string.len(sAttackTableName) < 1 then
							setValue("");
						end
						updateList();
					end
					function updateList()
						addItems(Rules_Tables.LargeColumnList);
					end

