string_columnh_item.script:
function onInit()
	node = window.getDatabaseNode();
	if node then
		if string.len(getValue()) == 0 then
			DB.setValue(node, "cost", "string", DB.getValue(node,"rural",""));
		end
		DB.deleteChild(node, "rural");
	end
end

